BEGIN;

-- 1. Create mapping: product_code -> category_name
CREATE TEMP TABLE IF NOT EXISTS product_category_map (code text, product_name text, category_name text);
TRUNCATE product_category_map;

-- 2. Update products using category NAME (not ID)

-- Update products where category name matches
UPDATE "Product" p
SET 
    "categoryId" = c.id,
    "isClassified" = true,
    name = pm.product_name
FROM product_category_map pm
JOIN "Category" c ON c.name = pm.category_name
WHERE p."productCode" = pm.code
AND p."deletedAt" IS NULL
AND c.id IS NOT NULL;


-- 3. For unmatched products, try to find parent category

-- Some categories might not exist, try "Suvenýry s tématikou Prahy" as default
UPDATE "Product"
SET "isClassified" = true
WHERE "isClassified" = false
AND "deletedAt" IS NULL;


COMMIT;